mapper.update:
update TB_WORK_ORDER_PROC
set    proc_status      = #{procStatus}
      ,prod_date        = isnull(CAST(#{prodDate} AS date), CONVERT(date, GETDATE()))
      ,storage_cd       = #{storageCd}
      ,manager_id       = #{managerId}
      ,test_no          = #{testNo}
      ,work_start_time  = getdate()
      ,upd_id           = #{userId}
      ,upd_dt           = getDate()
where  work_proc_id     = #{workProcId}
